import java.io.*;
import org.owasp.esapi.ESAPI;

public class XSSSecureCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            // Properly encoding user input using OWASP ESAPI to prevent XSS
            String encodedUserInput = ESAPI.encoder().encodeForHTML(userInput);
            System.out.println("<h1>Welcome, " + encodedUserInput + "!</h1>");
        } catch (IOException e) {
            System.err.println("Error reading user input");
        }
    }
}

